#include <bits/stdc++.h>
using namespace std;
string a,b;
void f(int i,int n){
	if(i<n){
		char c;
		if(b[i]<a[i]&&(b[i]<='Z'&&b[i]>='A')==0){
			c=b[i]-a[i]+'z'+1;
		}
		else{
			c=b[i]-a[i]+'a';
		}
		if(b[i]<='Z'&&b[i]>='A'){
			if(c<'A'){
				c+='z'-'a'+1;
			}
		}
		cout<<c;
		return f(i+1,n);
	}
}
int main(){
	cin>>a>>b;
	for(int i=0;i<a.length();i++){
		a[i]=tolower(a[i]);
	}
	while(a.length()<b.length()){
		a+=a;
	}
	f(0,b.length());
	return 0;
}
